var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"으으, 눈부셔.","JPN":"うう、眩しい。","ENG":"Ugh... The flashes are hurting my eyes.","TWN":"呃，太刺眼了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"검의 움직임을 눈으로 좇는 것도 버거울 정도야.","JPN":"剣の動きを目で追うことで精一杯だ。","ENG":"It's hard to follow their sword movements with the naked eye.","TWN":"靠肉眼已經有些跟不上劍的速度了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"저 모르스라는 그림자, 과거엔 얼마나 강한 카운터였던 거지?","JPN":"あのモールスというシャドウ、過去ではどれほど強いカウンターだったんだろうね？","ENG":"That Shadow, Mors, I wonder how powerful she was when she was a Counter.","TWN":"那個叫死神的暗影，過去究竟是多麼強大的制裁者？"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"아직도 일어서는 건가?","JPN":"まだ立ち上がるのか？","ENG":"Still getting back up?","TWN":"你還能站起來嗎？"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"타기리온을 쓰러트리기 전까지 난 쓰러지지 않는다.","JPN":"タギリオンを倒すまで我は倒れん。","ENG":"I will not fall before Thagirion is defeated.","TWN":"在打敗塔基里翁之前，我不會倒下。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"그런 뻔한 거짓말을 하다니.","JPN":"そのような見え透いた嘘をつくとは。","ENG":"Again with your lies.","TWN":"滿口謊言。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"죄인만이 걸치는 그 갑주를 내가 못 알아볼 거라 생각하나?","JPN":"罪人だけが身に着けるその鎧を我が知らないとでも思ったのか？","ENG":"Did you think I would fail to realize that your armor is only for sinners?","TWN":"以為我認不出你那只有罪人才能穿上的盔甲？"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"내 앞을 가로막는 죄수의 말을 신용할 가치는 없다.","JPN":"我の行く手を阻む罪人の言葉に信用の価値などない。","ENG":"I do not trust the words coming from a sinner who is blocking my path.","TWN":"一個擋我路的罪人說的話不值得相信。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"너의 존재가… 타기리온을 불러들이고 있으니…","JPN":"そなたの存在が……タギリオンを呼び寄せている……","ENG":"Your existence... is what is summoning Thagirion...","TWN":"你的出現……正在召喚塔基里翁……"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"나는 그저 막을 뿐이다.","JPN":"我はただ、防ぐだけだ。","ENG":"And I am here to stop that.","TWN":"我只想阻止她。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"끝났군요.","JPN":"終わりましたね。","ENG":"It is over.","TWN":"結束了。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"타기리온이 현실을 완전히 잠식하면, 당신이 지금껏 해온 노력은 모두 허사가 되겠죠.","JPN":"タギリオンが現実を完全に侵食すると、今までのあなたの努力は全部無駄になるでしょう。","ENG":"Once Thagirion completely consumes this world, everything you have done up until this moment will be in vain.","TWN":"一旦塔基里翁徹底吞噬了現世，你所有的努力都將付諸東流。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"감상이 어떠신가요?","JPN":"どんなお気持ちですか？","ENG":"How does that make you feel?","TWN":"不知你有何感想？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"클리파 차원을 틀어막는 방주의 에너지는 애초부터 무한하지 않았네.","JPN":"クリファ次元を封じ込めている箱舟のエネルギーは最初から無限ではなかったのだ。","ENG":"The Ark's energy that's blocking the Qlipha Dimension has never been infinite.","TWN":"方舟用來阻止逆卡巴拉次元的能量本來就不是無限的。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"언젠가 닥칠 일이란 건 알았지만, 조금 이르다는 감은 있군.","JPN":"いつかはこうなると思っていたが、少し早い気がするな。","ENG":"This was going to happen sooner or later, but it feels a little earlier than I had expected.","TWN":"我早就料到她回來，但比我的預期有些早而已。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"저런 꼴을 보고서도 아직 포기를 못한 건가요?","JPN":"あのありさまを見てもまだ、諦めがつかないのですか？","ENG":"You still have hope, after seeing what has happened?","TWN":"看到這些還沒有放棄嗎？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};